function QuestionPalette({

  sections,

  currentIndex,

  answers,

  onSelect

}) {

  return (

    <div
      style={{
        width: "250px",
        background: "#ffffff",
        padding: "20px",
        borderRadius: "12px",
        boxShadow:
          "0 2px 8px rgba(0,0,0,0.1)"
      }}
    >

      <h3>
        Question Palette
      </h3>

      <div
        style={{
          display: "grid",
          gridTemplateColumns:
            "repeat(3,1fr)",
          gap: "10px"
        }}
      >

        {
          sections.map(
            (
              section,
              index
            ) => {

              const answered =
                answers[
                  `${section.sectionNo}_0`
                ];

              let color =
                "#ef4444";

              if (
                answered
              ) {
                color =
                  "#22c55e";
              }

              if (
                currentIndex ===
                index
              ) {
                color =
                  "#2563eb";
              }

              return (

                <button
                  key={
                    section.sectionNo
                  }
                  onClick={() =>
                    onSelect(
                      index
                    )
                  }
                  style={{
                    padding:
                      "12px",
                    border:
                      "none",
                    borderRadius:
                      "8px",
                    background:
                      color,
                    color:
                      "#fff",
                    cursor:
                      "pointer",
                    fontWeight:
                      "600"
                  }}
                >
                  {
                    section.sectionNo
                  }
                </button>

              );
            }
          )
        }

      </div>

    </div>

  );
}

export default QuestionPalette;
